Here are the public test cases for feature2_2_wrap_display_name:
{
  "description": "Wrap a component's label with an enhancer name in the form 'wrapper(label)'.",
  "cases": [
    {
      "input": {
        "command": "wrap_display_name",
        "component": {
          "kind": "class_named",
          "name": "SomeComponent"
        },
        "wrapper": "someHoC"
      },
      "expected_output": "name=\"someHoC(SomeComponent)\"\n"
    },
    {
      "input": {
        "command": "wrap_display_name",
        "component": {
          "kind": "dom",
          "name": "button"
        },
        "wrapper": "wrap"
      },
      "expected_output": "name=\"wrap(button)\"\n"
    }
  ]
}

Here are the public test cases for feature3_2_default_props:
{
  "description": "Supply fallback property values that apply only when the incoming property is missing or undefined; any defined incoming value is preserved.",
  "cases": [
    {
      "input": {
        "command": "transform_props",
        "stages": [
          {
            "op": "defaults",
            "props": {
              "si": "do",
              "la": "fa"
            }
          }
        ],
        "props": {}
      },
      "expected_output": "la=\"fa\"\nsi=\"do\"\n"
    },
    {
      "input": {
        "command": "transform_props",
        "stages": [
          {
            "op": "defaults",
            "props": {
              "si": "do",
              "la": "fa"
            }
          }
        ],
        "props": {
          "la": "ti"
        }
      },
      "expected_output": "la=\"ti\"\nsi=\"do\"\n"
    }
  ]
}

Here are the public test cases for feature3_4_omit_props:
{
  "description": "Drop the named properties and keep the rest.",
  "cases": [
    {
      "input": {
        "command": "transform_props",
        "stages": [
          {
            "op": "omit",
            "keys": [
              "foo"
            ]
          }
        ],
        "props": {
          "foo": "foo",
          "className": "bar"
        }
      },
      "expected_output": "className=\"bar\"\n"
    },
    {
      "input": {
        "command": "transform_props",
        "stages": [
          {
            "op": "omit",
            "keys": [
              "foo",
              "bar"
            ]
          }
        ],
        "props": {
          "foo": "foo",
          "bar": "bar",
          "className": "bar"
        }
      },
      "expected_output": "className=\"bar\"\n"
    }
  ]
}
